 11→#include <stdint.h>
 12→#include <stdio.h>
 13→#include <stdlib.h>
 14→#include <float.h>
 15→
 16→/* ------------------------------------------------------------------ */
 17→/* Helpers                                                             */
 18→/* ------------------------------------------------------------------ */
 19→
 20→static inline uint32_t float_to_bits(float f)
 21→{
 22→    union { float f; uint32_t u; } u;
 23→    u.f = f;
 24→    return u.u;
 25→}
 26→
 27→static inline float bits_to_float(uint32_t u)
 28→{
 29→    union { float f; uint32_t u; } x;
 30→    x.u = u;
 31→    return x.f;
 32→}
 33→
 34→static inline int is_nan(float f)
 35→{
 36→    uint32_t b = float_to_bits(f);
 37→    return ((b & 0x7f800000u) == 0x7f800000u) && ((b & 0x007fffffu) != 0);
 38→}
 39→
 40→static inline int is_inf(float f)
 41→{
 42→    uint32_t b = float_to_bits(f);
 43→    return ((b & 0x7fffffffu) == 0x7f800000u);
 44→}
 45→
 46→/*
 47→ * Compute ULP distance between two floats.
 48→ * Returns -1 if either is NaN.
 49→ */
 50→static int32_t ulp_distance(float a, float b)
 51→{
 52→    if (is_nan(a) || is_nan(b))
 53→        return -1;
 54→
 55→    uint32_t ua = float_to_bits(a);
 56→    uint32_t ub = float_to_bits(b);
 57→
 58→    /* Convert to signed magnitude → two's complement for comparison */
 59→    int32_t ia = (int32_t)ua;
 60→    int32_t ib = (int32_t)ub;
 61→
 62→    if (ia < 0) ia = (int32_t)(0x80000000u - ua);
 63→    if (ib < 0) ib = (int32_t)(0x80000000u - ub);
 64→
 65→    int32_t diff = ia - ib;
 66→    return diff < 0 ? -diff : diff;
 67→}
 68→
 69→/* ------------------------------------------------------------------ */
 70→/* Test infrastructure                                                 */
 71→/* ------------------------------------------------------------------ */
 72→
 73→static int total_tests = 0;
 74→static int total_failures = 0;
 75→static int32_t max_ulp_seen = 0;
 76→
 77→static void check_sinf(float input, float expected, int32_t max_ulp, const char *label)
 78→{
 79→    float got = sinf(input);
 80→    total_tests++;
 81→
 82→    /* Both NaN → pass */
 83→    if (is_nan(expected) && is_nan(got))
 84→        return;
 85→
 86→    /* One NaN, other not → fail */
 87→    if (is_nan(expected) || is_nan(got)) {
 88→        printf("FAIL [%s]: sinf(%.8e) = %.8e [0x%08x], expected %.8e [0x%08x] (NaN mismatch)\n",
 89→               label, (double)input, (double)got, float_to_bits(got),
 90→               (double)expected, float_to_bits(expected));
 91→        total_failures++;
 92→        return;
 93→    }
 94→
 95→    int32_t ulp = ulp_distance(got, expected);
 96→
 97→    if (ulp > max_ulp_seen)
 98→        max_ulp_seen = ulp;
 99→
100→    if (ulp > max_ulp) {
101→        printf("FAIL [%s]: sinf(%.8e [0x%08x]) = %.8e [0x%08x], expected %.8e [0x%08x] (ulp=%d, max=%d)\n",
102→               label, (double)input, float_to_bits(input),
103→               (double)got, float_to_bits(got),
104→               (double)expected, float_to_bits(expected),
105→               (int)ulp, (int)max_ulp);
106→        total_failures++;
107→    }
108→}
109→
110→/*
111→ * Use double-precision sin as reference for sinf.
112→ * (float)sin((double)x) is correctly rounded for all but a handful of
113→ * inputs, so 1 ULP tolerance handles those.
114→ */
115→static void check_sinf_ref(float input, int32_t max_ulp, const char *label)
116→{
117→    float expected = (float)sin((double)input);
118→    check_sinf(input, expected, max_ulp, label);
119→}
