121→/* ------------------------------------------------------------------ */
122→/* 1. Exact / special value tests                                      */
123→/* ------------------------------------------------------------------ */
124→
125→static void test_zeros(void)
126→{
127→    printf("--- Zeros ---\n");
128→    /* sin(+0) = +0 */
129→    check_sinf(0.0f, 0.0f, 0, "+0");
130→    /* sin(-0) = -0 */
131→    check_sinf(-0.0f, -0.0f, 0, "-0");
132→
133→    /* Verify sign bit of zero results */
134→    float r_pos = sinf(0.0f);
135→    float r_neg = sinf(-0.0f);
136→    if (float_to_bits(r_pos) != 0x00000000u) {
137→        printf("FAIL [+0 sign]: sinf(+0) sign bit wrong: 0x%08x\n", float_to_bits(r_pos));
138→        total_failures++;
139→    }
140→    total_tests++;
141→    if (float_to_bits(r_neg) != 0x80000000u) {
142→        printf("FAIL [-0 sign]: sinf(-0) sign bit wrong: 0x%08x\n", float_to_bits(r_neg));
143→        total_failures++;
144→    }
145→    total_tests++;
146→}
147→
148→static void test_nan(void)
149→{
150→    printf("--- NaN ---\n");
151→    /* sin(NaN) = NaN */
152→    float qnan = bits_to_float(0x7fc00000u); /* quiet NaN */
153→    float snan = bits_to_float(0x7f800001u); /* signaling NaN */
154→    float neg_nan = bits_to_float(0xffc00000u);
155→
156→    check_sinf(qnan, qnan, 0, "qNaN");
157→    check_sinf(snan, qnan, 0, "sNaN");  /* sNaN should become qNaN */
158→    check_sinf(neg_nan, neg_nan, 0, "-NaN");
159→}
