161→static void test_infinity(void)
162→{
163→    printf("--- Infinity ---\n");
164→    /* sin(+Inf) = NaN */
165→    float pinf = bits_to_float(0x7f800000u);
166→    float ninf = bits_to_float(0xff800000u);
167→    float expected_nan = bits_to_float(0x7fc00000u);
168→
169→    check_sinf(pinf, expected_nan, 0, "+Inf");
170→    check_sinf(ninf, expected_nan, 0, "-Inf");
171→}
