173→/* ------------------------------------------------------------------ */
174→/* 2. Tiny values: sin(x) ≈ x                                         */
175→/* ------------------------------------------------------------------ */
176→
177→static void test_tiny(void)
178→{
179→    printf("--- Tiny values (sin(x) ~ x) ---\n");
180→
181→    /* Smallest denormal */
182→    check_sinf_ref(bits_to_float(0x00000001u), 1, "min_denorm");
183→    check_sinf_ref(bits_to_float(0x80000001u), 1, "-min_denorm");
184→
185→    /* Mid-range denormals */
186→    check_sinf_ref(bits_to_float(0x00400000u), 1, "mid_denorm");
187→    check_sinf_ref(bits_to_float(0x80400000u), 1, "-mid_denorm");
188→
189→    /* Max denormal */
190→    check_sinf_ref(bits_to_float(0x007fffffu), 1, "max_denorm");
191→    check_sinf_ref(bits_to_float(0x807fffffu), 1, "-max_denorm");
192→
193→    /* Smallest normal */
194→    check_sinf_ref(FLT_MIN, 1, "FLT_MIN");
195→    check_sinf_ref(-FLT_MIN, 1, "-FLT_MIN");
196→
197→    /* Very small normals where sin(x) = x exactly in float */
198→    check_sinf_ref(1.0e-20f, 1, "1e-20");
199→    check_sinf_ref(-1.0e-20f, 1, "-1e-20");
200→    check_sinf_ref(1.0e-10f, 1, "1e-10");
201→    check_sinf_ref(-1.0e-10f, 1, "-1e-10");
202→}
