204→/* ------------------------------------------------------------------ */
205→/* 3. Known mathematical values                                        */
206→/* ------------------------------------------------------------------ */
207→
208→static void test_known_values(void)
209→{
210→    printf("--- Known mathematical values ---\n");
211→
212→    /* pi/6, pi/4, pi/3, pi/2 and negatives */
213→    /* Using (float) casts of double constants for best-representable input */
214→    float pi_f = 3.14159265358979323846f;
215→    float pi_2 = 1.57079632679489661923f;
216→    float pi_3 = 1.04719755119659774615f;
217→    float pi_4 = 0.78539816339744830962f;
218→    float pi_6 = 0.52359877559829887308f;
219→
220→    check_sinf_ref(pi_6, 1, "pi/6");          /* ~ 0.5 */
221→    check_sinf_ref(pi_4, 1, "pi/4");          /* ~ sqrt(2)/2 */
222→    check_sinf_ref(pi_3, 1, "pi/3");          /* ~ sqrt(3)/2 */
223→    check_sinf_ref(pi_2, 1, "pi/2");          /* ~ 1.0 */
224→    check_sinf_ref(pi_f, 1, "pi");            /* ~ 0 (cancellation) */
225→    check_sinf_ref(2.0f * pi_f, 1, "2*pi");   /* ~ 0 (cancellation) */
226→
227→    /* Negative inputs */
228→    check_sinf_ref(-pi_6, 1, "-pi/6");
229→    check_sinf_ref(-pi_4, 1, "-pi/4");
230→    check_sinf_ref(-pi_2, 1, "-pi/2");
231→    check_sinf_ref(-pi_f, 1, "-pi");
232→
233→    /* 3*pi/2: sin = -1 */
234→    check_sinf_ref(3.0f * pi_2, 1, "3*pi/2");
235→
236→    /* Quadrant boundaries */
237→    check_sinf_ref(pi_2 + 0.001f, 1, "pi/2+eps");
238→    check_sinf_ref(pi_f + 0.001f, 1, "pi+eps");
239→    check_sinf_ref(pi_f - 0.001f, 1, "pi-eps");
240→}
