242→/* ------------------------------------------------------------------ */
243→/* 4. Large argument reduction                                         */
244→/* ------------------------------------------------------------------ */
245→
246→static void test_large_args(void)
247→{
248→    printf("--- Large arguments (argument reduction stress) ---\n");
249→
250→    /* Moderate multiples of pi */
251→    float vals[] = {
252→        10.0f, 100.0f, 1000.0f, 10000.0f, 100000.0f, 1000000.0f,
253→        -10.0f, -100.0f, -1000.0f, -10000.0f,
254→        /* Near-integer multiples of pi */
255→        3.14159265f * 10.0f,
256→        3.14159265f * 100.0f,
257→        3.14159265f * 1000.0f,
258→        /* Large values */
259→        1.0e10f, 1.0e20f, 1.0e30f,
260→        -1.0e10f, -1.0e20f, -1.0e30f,
261→        /* FLT_MAX */
262→        FLT_MAX, -FLT_MAX,
263→    };
264→
265→    char buf[64];
266→    int n = sizeof(vals) / sizeof(vals[0]);
267→    for (int i = 0; i < n; i++) {
268→        snprintf(buf, sizeof(buf), "large[%d]=%.4e", i, (double)vals[i]);
269→        check_sinf_ref(vals[i], 2, buf);
270→    }
271→}
