273→/* ------------------------------------------------------------------ */
274→/* 5. Quadrant transition points                                       */
275→/* ------------------------------------------------------------------ */
276→
277→static void test_quadrant_transitions(void)
278→{
279→    printf("--- Quadrant transition points ---\n");
280→
281→    /* Test values just around each quadrant boundary */
282→    float pi_2 = 1.5707963267948966f;
283→    float offsets[] = { -1e-3f, -1e-5f, -1e-7f, 0.0f, 1e-7f, 1e-5f, 1e-3f };
284→    int noff = sizeof(offsets) / sizeof(offsets[0]);
285→    char buf[64];
286→
287→    /* Boundaries at k*pi/2 for k = 1..8 */
288→    for (int k = 1; k <= 8; k++) {
289→        float boundary = (float)((double)k * (double)pi_2);
290→        for (int j = 0; j < noff; j++) {
291→            float x = boundary + offsets[j];
292→            snprintf(buf, sizeof(buf), "quad k=%d off=%d", k, j);
293→            check_sinf_ref(x, 1, buf);
294→        }
295→    }
296→}
