298→/* ------------------------------------------------------------------ */
299→/* 6. Sign symmetry: sin(-x) = -sin(x)                                */
300→/* ------------------------------------------------------------------ */
301→
302→static void test_symmetry(void)
303→{
304→    printf("--- Odd-function symmetry ---\n");
305→
306→    float vals[] = {
307→        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 2.5f, 3.0f, 3.5f,
308→        0.001f, 0.01f, 100.0f, 1e6f, 1e10f
309→    };
310→    char buf[64];
311→    int n = sizeof(vals) / sizeof(vals[0]);
312→
313→    for (int i = 0; i < n; i++) {
314→        float sp = sinf(vals[i]);
315→        float sn = sinf(-vals[i]);
316→        total_tests++;
317→
318→        /* Check that sin(-x) == -sin(x) exactly (bit-identical) */
319→        uint32_t bp = float_to_bits(sp);
320→        uint32_t bn = float_to_bits(sn);
321→
322→        if (bp != (bn ^ 0x80000000u)) {
323→            snprintf(buf, sizeof(buf), "sym[%.4e]", (double)vals[i]);
324→            printf("FAIL [%s]: sinf(x)=0x%08x, sinf(-x)=0x%08x (sign flip mismatch)\n",
325→                   buf, bp, bn);
326→            total_failures++;
327→        }
328→    }
329→}
