331→/* ------------------------------------------------------------------ */
332→/* 7. Range bound: |sin(x)| <= 1                                       */
333→/* ------------------------------------------------------------------ */
334→
335→static void test_range_bound(void)
336→{
337→    printf("--- Range bound |sin(x)| <= 1 ---\n");
338→
339→    /* Sweep a bunch of values and verify output is in [-1, 1] */
340→    uint32_t step = 0x00100000u; /* ~1M steps across positive floats */
341→    int violations = 0;
342→    int checked = 0;
343→
344→    for (uint32_t bits = 0x00800000u; bits < 0x7f800000u; bits += step) {
345→        float x = bits_to_float(bits);
346→        float r = sinf(x);
347→        checked++;
348→
349→        if (!is_nan(r) && (r > 1.0f || r < -1.0f)) {
350→            if (violations < 10) {
351→                printf("FAIL [range]: sinf(%.8e) = %.8e (out of [-1,1])\n",
352→                       (double)x, (double)r);
353→            }
354→            violations++;
355→        }
356→    }
357→
358→    total_tests += checked;
359→    total_failures += violations;
360→    printf("  Checked %d values, %d range violations\n", checked, violations);
361→}
362→
363→/* ------------------------------------------------------------------ */
364→/* 8. Systematic ULP sweep across key intervals                        */
365→/* ------------------------------------------------------------------ */
366→
367→static void test_ulp_sweep(void)
368→{
369→    printf("--- Systematic ULP sweep ---\n");
370→
371→    /*
372→     * Sweep [0, 4*pi] in fine steps (covers 2 full periods).
373→     * Also sweep some negative range.
374→     */
375→    int32_t local_max_ulp = 0;
376→    int count = 0;
377→    int fail_count = 0;
378→    char buf[64];
379→
380→    /* [0, 4*pi] with 100k steps */
381→    float lo = 0.0f;
382→    float hi = 4.0f * 3.14159265358979323846f;
383→    int nsteps = 100000;
384→    float step = (hi - lo) / (float)nsteps;
385→
386→    for (int i = 0; i <= nsteps; i++) {
387→        float x = lo + (float)i * step;
388→        float got = sinf(x);
389→        float ref = (float)sin((double)x);
390→        int32_t ulp = ulp_distance(got, ref);
391→
392→        total_tests++;
393→        count++;
394→
395→        if (ulp > local_max_ulp)
396→            local_max_ulp = ulp;
397→
398→        if (ulp > 1) {
399→            if (fail_count < 5) {
400→                snprintf(buf, sizeof(buf), "sweep+[%d]", i);
401→                printf("FAIL [%s]: sinf(%.8e) = %.8e, ref=%.8e, ulp=%d\n",
402→                       buf, (double)x, (double)got, (double)ref, (int)ulp);
403→            }
404→            fail_count++;
405→            total_failures++;
406→        }
407→    }
408→
409→    /* [-4*pi, 0] with 100k steps */
410→    lo = -4.0f * 3.14159265358979323846f;
411→    hi = 0.0f;
412→    for (int i = 0; i <= nsteps; i++) {
413→        float x = lo + (float)i * step;
414→        float got = sinf(x);
415→        float ref = (float)sin((double)x);
416→        int32_t ulp = ulp_distance(got, ref);
417→
418→        total_tests++;
419→        count++;
420→
421→        if (ulp > local_max_ulp)
422→            local_max_ulp = ulp;
423→
424→        if (ulp > 1) {
425→            if (fail_count < 10) {
426→                snprintf(buf, sizeof(buf), "sweep-[%d]", i);
427→                printf("FAIL [%s]: sinf(%.8e) = %.8e, ref=%.8e, ulp=%d\n",
428→                       buf, (double)x, (double)got, (double)ref, (int)ulp);
429→            }
430→            fail_count++;
431→            total_failures++;
432→        }
433→    }
434→
435→    if (local_max_ulp > max_ulp_seen)
436→        max_ulp_seen = local_max_ulp;
437→
438→    printf("  Swept %d values, max ULP = %d, failures (>1 ULP) = %d\n",
439→           count, (int)local_max_ulp, fail_count);
440→}
