442→/* ------------------------------------------------------------------ */
443→/* 9. Problematic float bit patterns (worst-case for argument reduction) */
444→/* ------------------------------------------------------------------ */
445→
446→static void test_worst_case_reduction(void)
447→{
448→    printf("--- Worst-case argument reduction ---\n");
449→
450→    /*
451→     * Values near exact multiples of pi/2 where cancellation is severe.
452→     * These are known hard cases for sinf argument reduction.
453→     */
454→    float hard_cases[] = {
455→        /* Near pi: sin(pi) ≈ 0, massive cancellation */
456→        3.1415927f, /* closest float to pi */
457→        3.1415925f, /* float below pi */
458→        3.1415929f, /* float above pi */
459→
460→        /* Near 2*pi */
461→        6.2831853f,
462→        6.2831855f,
463→
464→        /* Near pi/2 where cos is used internally */
465→        1.5707964f,
466→        1.5707963f,
467→
468→        /* Specific bit patterns known to stress reduction */
469→        bits_to_float(0x40490fdbu), /* pi as float */
470→        bits_to_float(0x40c90fdbu), /* 2*pi as float */
471→        bits_to_float(0x4096cbe4u), /* 3*pi/2 */
472→
473→        /* Powers of 2 near pi multiples */
474→        4.0f,   /* slightly > pi */
475→        8.0f,   /* slightly > 2*pi + small */
476→        16.0f,
477→        32.0f,
478→        64.0f,
479→        128.0f,
480→        256.0f,
481→    };
482→    char buf[64];
483→    int n = sizeof(hard_cases) / sizeof(hard_cases[0]);
484→
485→    for (int i = 0; i < n; i++) {
486→        snprintf(buf, sizeof(buf), "hard[%d]=%.8e", i, (double)hard_cases[i]);
487→        check_sinf_ref(hard_cases[i], 1, buf);
488→        /* Also test negative */
489→        snprintf(buf, sizeof(buf), "hard[%d]=-%.8e", i, (double)hard_cases[i]);
490→        check_sinf_ref(-hard_cases[i], 1, buf);
491→    }
492→}
493→
494→/* ------------------------------------------------------------------ */
495→/* 10. Monotonicity checks                                             */
496→/* ------------------------------------------------------------------ */
497→
498→static void test_monotonicity(void)
499→{
500→    printf("--- Monotonicity in [0, pi/2] ---\n");
501→
502→    /*
503→     * sin is strictly increasing on [0, pi/2].
504→     * Walk consecutive floats and verify non-decreasing.
505→     */
506→    float start = 0.0f;
507→    float end = 1.5707963f; /* just under pi/2 */
508→    uint32_t start_bits = float_to_bits(start);
509→    uint32_t end_bits = float_to_bits(end);
510→    int violations = 0;
511→    int checked = 0;
512→
513→    /* Step by 256 ULPs to keep runtime reasonable */
514→    uint32_t step = 256;
515→    float prev = sinf(bits_to_float(start_bits));
516→
517→    for (uint32_t b = start_bits + step; b <= end_bits; b += step) {
518→        float x = bits_to_float(b);
519→        float cur = sinf(x);
520→        checked++;
521→
522→        if (cur < prev) {
523→            if (violations < 5) {
524→                printf("FAIL [mono]: sinf(%.8e)=%.8e < sinf(prev)=%.8e\n",
525→                       (double)x, (double)cur, (double)prev);
526→            }
527→            violations++;
528→        }
529→        prev = cur;
530→    }
531→
532→    total_tests += checked;
533→    total_failures += violations;
534→    printf("  Checked %d consecutive pairs, %d monotonicity violations\n",
535→           checked, violations);
536→}
537→
538→/* ------------------------------------------------------------------ */
539→/* 11. Continuity: adjacent floats should not produce wild jumps        */
540→/* ------------------------------------------------------------------ */
541→
542→static void test_continuity(void)
543→{
544→    printf("--- Continuity (adjacent float inputs) ---\n");
545→
546→    /*
547→     * For adjacent float inputs x and nextafter(x), the outputs should
548→     * differ by at most a few ULP (bounded by the derivative |cos(x)| * 1 ULP(x)).
549→     * We just flag cases where the output jumps by more than 4096 ULPs.
550→     */
551→    float test_points[] = {
552→        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 3.0f, 3.14f, 4.5f, 6.0f, 10.0f
553→    };
554→    int n = sizeof(test_points) / sizeof(test_points[0]);
555→    int violations = 0;
556→    char buf[64];
557→
558→    for (int i = 0; i < n; i++) {
559→        float x = test_points[i];
560→        /* Check 100 consecutive floats around this point */
561→        uint32_t base = float_to_bits(x);
562→        float prev_r = sinf(bits_to_float(base));
563→
564→        for (uint32_t j = 1; j <= 100; j++) {
565→            float cur_x = bits_to_float(base + j);
566→            float cur_r = sinf(cur_x);
567→            int32_t output_ulp = ulp_distance(prev_r, cur_r);
568→            total_tests++;
569→
570→            if (output_ulp > 4096 && !is_nan(prev_r) && !is_nan(cur_r)) {
571→                if (violations < 5) {
572→                    snprintf(buf, sizeof(buf), "cont near %.4e +%d", (double)x, (int)j);
573→                    printf("FAIL [%s]: output jump of %d ULP\n", buf, (int)output_ulp);
574→                }
575→                violations++;
576→                total_failures++;
577→            }
578→            prev_r = cur_r;
579→        }
580→    }
581→
582→    printf("  Checked %d adjacent pairs, %d continuity violations\n",
583→           n * 100, violations);
584→}
585→
586→/* ------------------------------------------------------------------ */
587→/* 12. Exhaustive sweep of small range [0, pi/4]                       */
588→/* ------------------------------------------------------------------ */
589→
590→static void test_exhaustive_small(void)
591→{
592→    printf("--- Exhaustive [0, pi/4] every 16 ULP ---\n");
593→
594→    /*
595→     * pi/4 ≈ 0.7854 → 0x3f490fdb
596→     * Walk every 16th float in [0, pi/4] and check against double ref.
597→     */
598→    uint32_t end_bits = 0x3f490fdbu; /* pi/4 */
599→    int32_t local_max_ulp = 0;
600→    int count = 0;
601→    int fail_count = 0;
602→
603→    for (uint32_t b = 0; b <= end_bits; b += 16) {
604→        float x = bits_to_float(b);
605→        float got = sinf(x);
606→        float ref = (float)sin((double)x);
607→        int32_t ulp = ulp_distance(got, ref);
608→
609→        total_tests++;
610→        count++;
611→
612→        if (ulp > local_max_ulp)
613→            local_max_ulp = ulp;
614→
615→        if (ulp > 1) {
616→            if (fail_count < 5) {
617→                printf("FAIL [exh]: sinf(%.8e [0x%08x]) = 0x%08x, ref=0x%08x, ulp=%d\n",
618→                       (double)x, b, float_to_bits(got), float_to_bits(ref), (int)ulp);
619→            }
620→            fail_count++;
621→            total_failures++;
622→        }
623→    }
624→
625→    if (local_max_ulp > max_ulp_seen)
626→        max_ulp_seen = local_max_ulp;
627→
628→    printf("  Checked %d values, max ULP = %d, failures = %d\n",
629→           count, (int)local_max_ulp, fail_count);
630→}
631→
632→/* ------------------------------------------------------------------ */
633→/* Main                                                                */
634→/* ------------------------------------------------------------------ */
635→
636→int main(void)
637→{
638→    printf("=== sinf() comprehensive accuracy test ===\n\n");
639→
640→    test_zeros();
641→    test_nan();
642→    test_infinity();
643→    test_tiny();
644→    test_known_values();
645→    test_large_args();
646→    test_quadrant_transitions();
647→    test_symmetry();
648→    test_range_bound();
649→    test_ulp_sweep();
650→    test_worst_case_reduction();
651→    test_monotonicity();
652→    test_continuity();
653→    test_exhaustive_small();
654→
655→    printf("\n=== Summary ===\n");
656→    printf("Total tests:    %d\n", total_tests);
657→    printf("Total failures: %d\n", total_failures);
658→    printf("Max ULP seen:   %d\n", (int)max_ulp_seen);
659→
660→    if (total_failures == 0)
661→        printf("PASSED\n");
662→    else
663→        printf("FAILED\n");
664→
665→    return total_failures > 0 ? 1 : 0;
666→}
