int main(void)
{
    printf("=== sinf() comprehensive accuracy test ===\n\n");

    test_zeros();
    test_nan();
    test_infinity();
    test_tiny();
    test_known_values();
    test_large_args();
    test_quadrant_transitions();
    test_symmetry();
    test_range_bound();
    test_ulp_sweep();
    test_worst_case_reduction();
    test_monotonicity();
    test_continuity();
    test_exhaustive_small();

    printf("\n=== Summary ===\n");
    printf("Total tests:    %d\n", total_tests);
    printf("Total failures: %d\n", total_failures);
    printf("Max ULP seen:   %d\n", (int)max_ulp_seen);

    if (total_failures == 0)
        printf("PASSED\n");
    else
        printf("FAILED\n");

    return total_failures > 0 ? 1 : 0;
}
